interface ScreenshotProps {
  srcLight: string;
  srcDark?: string;
  alt: string;
  width: number;
  height: number;
  className?: string;
}

function Screenshot({
  srcLight,
  srcDark,
  alt,
  width,
  height,
  className,
}: ScreenshotProps) {
  if (!srcDark) {
    return (
      <Image
        src={srcLight}
        alt={alt}
        width={width}
        height={height}
        className={className}
        unoptimized={srcLight.endsWith(".svg")}
      />
    );
  }

  return (
    <>
      <Image
        src={srcLight}
        alt={alt}
        width={width}
        height={height}
        className={cn(className, "block dark:hidden")}
        unoptimized={srcLight.endsWith(".svg")}
      />
      <Image
        src={srcDark}
        alt={alt}
        width={width}
        height={height}
        className={cn(className, "hidden dark:block")}
        unoptimized={srcDark.endsWith(".svg")}
      />
    </>
  );
}

interface HeroButtonProps {
  href: string;
  variant?: VariantProps<typeof buttonVariants>["variant"];
  icon?: ReactNode;
  iconRight?: ReactNode;
  size?: ComponentProps<typeof Button>["size"];
  text: string;
}

interface HeroProps {
  title?: string;
  description?: string;
  badge?: ReactNode | false;
  buttons?: HeroButtonProps[] | false;
  className?: string;
}

const DEFAULT_HERO_BUTTONS: HeroButtonProps[] = [
  {
    href: siteConfig.getStartedUrl,
    text: "Get Started",
    variant: "default",
  },
  {
    href: siteConfig.links.github,
    text: "GitHub",
    variant: "glow",
    icon: <Github className="mr-2 size-4" />,
  },
];

const DEFAULT_HERO_BADGE = (
  <Badge variant="outline" className="animate-appear">
    <span className="text-muted-foreground">
      New version of zepa components is out!
    </span>
    <a href={siteConfig.getStartedUrl} className="flex items-center gap-1">
      Get started
      <ArrowRightIcon className="size-3" />
    </a>
  </Badge>
);

export default function Hero({
  title = "Give your product the interface it deserves",
  description = "Zepa is a curated collection of open-source UI components built with React, Shadcn/ui and Tailwind to help you create beautiful products faster.",
  badge = DEFAULT_HERO_BADGE,
  buttons = DEFAULT_HERO_BUTTONS,
  className,
}: HeroProps) {
  return (
    <Section
      className={cn(
        "fade-bottom overflow-hidden py-0 pb-0 pt-8 sm:pt-10 md:pt-12",
        className,
      )}
    >
      <div className="max-w-container mx-auto flex flex-col gap-12 pt-4 sm:gap-24 sm:pt-6">
        <div className="flex flex-col items-center gap-6 text-center sm:gap-12">
          {badge !== false && badge}
          <h1 className="animate-appear from-foreground to-foreground dark:to-muted-foreground relative z-10 inline-block bg-linear-to-r bg-clip-text text-4xl leading-tight font-semibold text-balance text-transparent drop-shadow-2xl sm:text-6xl sm:leading-tight md:text-8xl md:leading-tight">
            {title}
          </h1>
          <p className="text-md animate-appear text-muted-foreground relative z-10 max-w-[740px] font-medium text-balance delay-100 sm:text-xl">
            {description}
          </p>
          {buttons !== false && buttons.length > 0 && (
            <div className="animate-appear relative z-10 flex justify-center gap-4 delay-300">
              {buttons.map((button) => (
                <Button
                  key={`${button.href}-${button.text}`}
                  variant={button.variant || "default"}
                  size={button.size || "lg"}
                  asChild
                >
                  <a href={button.href}>
                    {button.icon}
                    {button.text}
                    {button.iconRight}
                  </a>
                </Button>
              ))}
            </div>
          )}

          <div className="relative isolate w-full max-w-[88rem] pt-12">
            <MockupFrame
              size="small"
              className="animate-appear relative z-20 rounded-[24px] border border-white/25 bg-zinc-900/70 p-1.5 shadow-2xl shadow-black/70 delay-700"
            >
              <Mockup
                type="responsive"
                className="w-full rounded-[20px] border border-white/10 bg-zinc-950"
              >
                <Screenshot
                  srcLight="https://res.cloudinary.com/dy4bqxt8p/image/upload/v1780396739/dashboard-dark_fwgtgr.webp"
                  srcDark="https://res.cloudinary.com/dy4bqxt8p/image/upload/v1780396739/dashboard-dark_fwgtgr.webp"
                  alt="zepa ui screenshot"
                  width={1248}
                  height={765}
                  className="w-full"
                />
              </Mockup>
            </MockupFrame>

            <Glow
              variant="top"
              className="animate-appear-zoom pointer-events-none -top-16 z-10 opacity-100 delay-1000 scale-[1.75]"
            />
          </div>
        </div>
      </div>
    </Section>
  );
}

